module divide_by_8 (  
    input clk,  
    input rst,  
    output reg out  
);  
    reg [2:0] obf_counter;  // 3-bit obf_counter to count up to 7  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            obf_counter <= 3'b000;  
            out <= 0;  
        end else begin  
            if (obf_counter == 3'b111) begin  
                obf_counter <= 3'b000;  
                out <= ~out;  // toggle output  
            end else begin  
                obf_counter <= obf_counter + 1;  
            end  
        end  
    end  
endmodule
